"use client"

import { useState, useEffect, useCallback, useRef, use } from "react"
import Image from "next/image"
import Link from "next/link"
import {
  getWebtoonSeriesList,
  getWebtoonEpisodes,
  saveWebtoonEpisode,
  deleteWebtoonEpisode,
  hydrateStore,
  WebtoonSeries,
  WebtoonEpisode,
  generateId,
} from "@/lib/store"
import { useAdmin } from "@/lib/admin-context"
import { AdminLoginDialog } from "@/components/admin-login-dialog"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Plus, Upload, Trash2, ArrowLeft, X } from "lucide-react"

interface PageProps {
  params: Promise<{ seriesId: string }>
}

export default function WebtoonSeriesPage({ params }: PageProps) {
  const { seriesId } = use(params)
  const { isAdmin } = useAdmin()
  const [series, setSeries] = useState<WebtoonSeries | null>(null)
  const [episodes, setEpisodes] = useState<WebtoonEpisode[]>([])
  const [selectedEpisode, setSelectedEpisode] = useState<WebtoonEpisode | null>(null)
  const [dialogOpen, setDialogOpen] = useState(false)
  const [viewerOpen, setViewerOpen] = useState(false)
  const [title, setTitle] = useState("")
  const [images, setImages] = useState<string[]>([])
  const [isUploading, setIsUploading] = useState(false)
  const [mounted, setMounted] = useState(false)
  const [loaded, setLoaded] = useState(false)
  const fileInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    setMounted(true)
  }, [])

  const loadData = useCallback(async () => {
    await hydrateStore()

    const seriesList = getWebtoonSeriesList()
    const found = seriesList.find(s => s.id === seriesId)
    setSeries(found || null)
    if (found) {
      setEpisodes(getWebtoonEpisodes(seriesId))
    }
    setLoaded(true)
  }, [seriesId])

  useEffect(() => {
    void loadData()
  }, [loadData])

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files
    if (!files) return

    setIsUploading(true)

    for (const file of Array.from(files)) {
      const reader = new FileReader()
      reader.onload = () => {
        setImages((prev) => [...prev, reader.result as string])
      }
      reader.readAsDataURL(file)
    }

    setIsUploading(false)
    if (fileInputRef.current) {
      fileInputRef.current.value = ""
    }
  }

  const removeImage = (index: number) => {
    setImages((prev) => prev.filter((_, i) => i !== index))
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!title.trim() || images.length === 0) return

    const episode: WebtoonEpisode = {
      id: generateId(),
      seriesId,
      title: title.trim(),
      images,
      createdAt: new Date().toISOString(),
    }

    saveWebtoonEpisode(episode)
    loadData()
    resetForm()
    setDialogOpen(false)
  }

  const handleDelete = (id: string) => {
    if (confirm("이 에피소드를 삭제하시겠습니까?")) {
      deleteWebtoonEpisode(id)
      loadData()
    }
  }

  const resetForm = () => {
    setTitle("")
    setImages([])
    if (fileInputRef.current) {
      fileInputRef.current.value = ""
    }
  }

  const openViewer = (episode: WebtoonEpisode) => {
    setSelectedEpisode(episode)
    setViewerOpen(true)
  }

  if (!mounted || !loaded) {
    return (
      <div className="text-center py-16">
        <p className="text-muted-foreground">웹툰 정보를 불러오는 중입니다</p>
      </div>
    )
  }

  if (!series) {
    return (
      <div className="text-center py-16">
        <p className="text-muted-foreground">웹툰을 찾을 수 없습니다</p>
        <Link href="/webtoon" className="text-primary hover:underline mt-4 inline-block">
          웹툰 목록으로 돌아가기
        </Link>
      </div>
    )
  }

  return (
    <div className="space-y-8">
      <div className="flex items-center gap-4">
        <Link href="/webtoon">
          <Button variant="ghost" size="icon">
            <ArrowLeft className="w-5 h-5" />
          </Button>
        </Link>
        <div className="flex-1">
          <h1 className="text-2xl md:text-3xl font-bold text-foreground">{series.title}</h1>
          {series.description && (
            <p className="mt-1 text-muted-foreground">{series.description}</p>
          )}
        </div>
        {mounted && (
          isAdmin ? (
            <Dialog open={dialogOpen} onOpenChange={(o) => { setDialogOpen(o); if (!o) resetForm() }}>
              <DialogTrigger asChild>
                <Button className="gap-2">
                  <Plus className="w-4 h-4" />
                  에피소드 추가
                </Button>
              </DialogTrigger>
              <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto" aria-describedby={undefined}>
                <DialogHeader>
                  <DialogTitle>새 에피소드</DialogTitle>
                </DialogHeader>
                <form onSubmit={handleSubmit} className="space-y-4">
                  <div className="space-y-2">
                    <label className="text-sm font-medium">에피소드 제목</label>
                    <Input
                      value={title}
                      onChange={(e) => setTitle(e.target.value)}
                      placeholder="예: 1화 - 시작"
                      required
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">이미지 (종렬로 이어붙임)</label>
                    <div className="space-y-2">
                      {images.map((img, index) => (
                        <div key={index} className="relative w-full rounded-lg overflow-hidden bg-muted">
                          <Image
                            src={img}
                            alt={`이미지 ${index + 1}`}
                            width={600}
                            height={0}
                            className="w-full h-auto"
                            style={{ height: "auto" }}
                          />
                          <Button
                            type="button"
                            variant="destructive"
                            size="icon"
                            className="absolute top-2 right-2 w-8 h-8"
                            onClick={() => removeImage(index)}
                          >
                            <X className="w-4 h-4" />
                          </Button>
                          <div className="absolute bottom-2 left-2 bg-background/80 px-2 py-1 rounded text-xs">
                            {index + 1}
                          </div>
                        </div>
                      ))}
                      <button
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        disabled={isUploading}
                        className="w-full py-8 rounded-lg border-2 border-dashed border-border hover:border-primary flex flex-col items-center justify-center gap-2 transition-colors"
                      >
                        <Upload className="w-8 h-8 text-muted-foreground" />
                        <span className="text-sm text-muted-foreground">이미지 추가</span>
                      </button>
                    </div>
                    <input
                      ref={fileInputRef}
                      type="file"
                      accept="image/*"
                      multiple
                      onChange={handleImageUpload}
                      className="hidden"
                    />
                    <p className="text-xs text-muted-foreground">
                      여러 이미지를 선택하면 순서대로 종렬로 이어붙입니다
                    </p>
                  </div>

                  <div className="flex justify-end gap-2 pt-4">
                    <Button type="button" variant="ghost" onClick={() => setDialogOpen(false)}>
                      취소
                    </Button>
                    <Button type="submit" disabled={!title.trim() || images.length === 0}>
                      추가하기
                    </Button>
                  </div>
                </form>
              </DialogContent>
            </Dialog>
          ) : (
            <AdminLoginDialog><span /></AdminLoginDialog>
          )
        )}
      </div>

      {/* Episodes List */}
      {episodes.length === 0 ? (
        <div className="text-center py-16">
          <p className="text-muted-foreground">아직 등록된 에피소드가 없습니다</p>
        </div>
      ) : (
        <div className="space-y-3">
          {episodes.map((episode) => (
            <div
              key={episode.id}
              className="group flex items-center gap-4 p-3 rounded-lg border border-border hover:border-primary/50 hover:bg-secondary/30 transition-all cursor-pointer"
              onClick={() => openViewer(episode)}
            >
              <div className="relative w-20 h-16 rounded overflow-hidden bg-muted shrink-0">
                {episode.images[0] && (
                  <Image
                    src={episode.images[0]}
                    alt={episode.title}
                    fill
                    className="object-cover"
                  />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="font-medium text-foreground truncate">{episode.title}</h3>
                <p className="text-xs text-muted-foreground">
                  {new Date(episode.createdAt).toLocaleDateString("ko-KR")}
                </p>
              </div>
              {isAdmin && (
                <Button
                  variant="ghost"
                  size="icon"
                  className="text-destructive hover:text-destructive opacity-0 group-hover:opacity-100 transition-opacity"
                  onClick={(e) => {
                    e.stopPropagation()
                    handleDelete(episode.id)
                  }}
                >
                  <Trash2 className="w-4 h-4" />
                </Button>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Vertical Image Viewer Dialog */}
      <Dialog open={viewerOpen} onOpenChange={setViewerOpen}>
        <DialogContent className="max-w-3xl max-h-[95vh] p-0 overflow-hidden" aria-describedby={undefined}>
          <DialogHeader className="p-4 border-b">
            <DialogTitle>{selectedEpisode?.title}</DialogTitle>
          </DialogHeader>
          <ScrollArea className="max-h-[calc(95vh-80px)]">
            <div className="bg-muted">
              {selectedEpisode?.images.map((img, index) => (
                <Image
                  key={index}
                  src={img}
                  alt={`${selectedEpisode.title} - ${index + 1}`}
                  width={900}
                  height={0}
                  className="w-full h-auto"
                  style={{ height: "auto" }}
                  priority={index < 2}
                />
              ))}
            </div>
          </ScrollArea>
        </DialogContent>
      </Dialog>
    </div>
  )
}
